/// <summary>
/// Class entry point. The system will call this method when a designated menu
/// is selected or when execution starts and this class is set as the startup class.
/// </summary>
/// <param name = "_args">The specified arguments.</param>
public static void main(Args _args)
{
    ETG_ARAP_MSGHEADER header;

    ETG_GeneralJournalIntegration  generalJournalIntegration = new ETG_GeneralJournalIntegration();

    while select header
        where header.ETGIntegrationsStatus == ETGIntegrationStatus::Unprocessed

    if(header.ETGLOG == "" && header.ETGDocuType == "INV")
    {
        generalJournalIntegration.postInvoice(header.ETGARAPREF);
    }
    else if(header.ETGLOG == "" && header.ETGDocuType == "VCH")
    {
        generalJournalIntegration.PostVCH(header.ETGARAPREF);
    }
    else if(header.ETGLOG == "" && header.ETGDocuType == "ARCN")
    {
        generalJournalIntegration.PostARCN(header.ETGARAPREF);
    }
    else if(header.ETGLOG == "" && header.ETGDocuType == "ARDN")
    {
        generalJournalIntegration.PostARDN(header.ETGARAPREF);
    }
    else if(header.ETGLOG == "" && header.ETGDocuType == "APDN")
    {
        generalJournalIntegration.PostAPDN(header.ETGARAPREF);
    }
    else if(header.ETGLOG == "" && header.ETGDocuType == "APCN")
    {
        generalJournalIntegration.PostAPCN(header.ETGARAPREF);
    }
}
